// Devuelve la etiqueta traducida; si no existe la traducción, devuelve la clave original.
export function trItem(map, key, idioma) {
  if (!idioma || idioma === 'es') return key;
  return map[key]?.[idioma] ?? key;
}

// Convierte un array de claves canónicas en un array de etiquetas traducidas.
export function trArray(map, keys, idioma) {
  return keys.map(k => trItem(map, k, idioma));
}

